package server

import (
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent/executeloop"
)

const (
	workerDesiredStateVersion = 1
	defaultWorkerCount        = 0
	defaultWorkerProfile      = "default"
	defaultWorkerIdleInterval = 30 * time.Second
	defaultRestartBackoff     = 30 * time.Second
	defaultRestartBackoffMax  = 10 * time.Minute
	defaultRestartLimit       = 6
)

// WorkerRestartPolicy controls whether the supervisor should restart
// unexpected exits and how aggressively it may retry.
type WorkerRestartPolicy struct {
	Enabled            bool                 `json:"enabled"`
	MaxRestartsPerHour int                  `json:"max_restarts_per_hour"`
	Backoff            executeloop.Duration `json:"backoff"`
	BackoffMax         executeloop.Duration `json:"backoff_max"`
}

// WorkerDesiredState is the durable desired-state model persisted at
// .ddx/workers/desired.json.
type WorkerDesiredState struct {
	Version      int                   `json:"version"`
	ProjectRoot  string                `json:"project_root"`
	DesiredCount int                   `json:"desired_count"`
	DefaultSpec  ExecuteLoopWorkerSpec `json:"default_spec"`
	Restart      WorkerRestartPolicy   `json:"restart"`
	UpdatedAt    time.Time             `json:"updated_at"`
}

// DefaultWorkerDesiredState returns a sane desired-state skeleton for a
// project. Callers normally override DesiredCount before saving.
func DefaultWorkerDesiredState(projectRoot string) WorkerDesiredState {
	state := WorkerDesiredState{
		Version:      workerDesiredStateVersion,
		ProjectRoot:  projectRoot,
		DesiredCount: defaultWorkerCount,
		DefaultSpec: ExecuteLoopWorkerSpec{
			Mode:         executeloop.ModeWatch,
			IdleInterval: executeloop.Duration{Duration: defaultWorkerIdleInterval},
			Profile:      defaultWorkerProfile,
		},
		Restart: WorkerRestartPolicy{
			Enabled:            true,
			MaxRestartsPerHour: defaultRestartLimit,
			Backoff:            executeloop.Duration{Duration: defaultRestartBackoff},
			BackoffMax:         executeloop.Duration{Duration: defaultRestartBackoffMax},
		},
		UpdatedAt: time.Now().UTC(),
	}
	state.DefaultSpec.ApplyDefaults()
	return state
}

// ApplyDefaults fills in sane defaults without mutating explicit operator
// choices. The project root is injected by the caller so the file can be
// validated independently of where it was loaded from.
func (s *WorkerDesiredState) ApplyDefaults(projectRoot string) {
	if s == nil {
		return
	}
	if s.Version == 0 {
		s.Version = workerDesiredStateVersion
	}
	if s.ProjectRoot == "" {
		s.ProjectRoot = projectRoot
	}
	if s.DefaultSpec.Mode == "" {
		s.DefaultSpec.Mode = executeloop.ModeWatch
	}
	if s.DefaultSpec.Mode == executeloop.ModeWatch && s.DefaultSpec.IdleInterval.Duration == 0 {
		s.DefaultSpec.IdleInterval = executeloop.Duration{Duration: defaultWorkerIdleInterval}
	}
	if s.DefaultSpec.Profile == "" {
		s.DefaultSpec.Profile = defaultWorkerProfile
	}
	s.DefaultSpec.ApplyDefaults()

	if s.Restart.Enabled {
		if s.Restart.MaxRestartsPerHour == 0 {
			s.Restart.MaxRestartsPerHour = defaultRestartLimit
		}
		if s.Restart.Backoff.Duration == 0 {
			s.Restart.Backoff = executeloop.Duration{Duration: defaultRestartBackoff}
		}
		if s.Restart.BackoffMax.Duration == 0 {
			s.Restart.BackoffMax = executeloop.Duration{Duration: defaultRestartBackoffMax}
		}
	}
}

// Validate checks the normalized desired state for internal consistency.
func (s WorkerDesiredState) Validate() error {
	if s.Version != workerDesiredStateVersion {
		return fmt.Errorf("worker desired state: unsupported version %d", s.Version)
	}
	if s.ProjectRoot == "" {
		return fmt.Errorf("worker desired state: project_root is required")
	}
	if s.DesiredCount < 0 {
		return fmt.Errorf("worker desired state: desired_count must be >= 0")
	}
	if s.DefaultSpec.Mode == "" {
		return fmt.Errorf("worker desired state: default_spec.mode is required")
	}
	if err := s.DefaultSpec.Validate(); err != nil {
		return fmt.Errorf("worker desired state: default_spec invalid: %w", err)
	}
	if s.Restart.Enabled {
		if s.Restart.MaxRestartsPerHour <= 0 {
			return fmt.Errorf("worker desired state: restart.max_restarts_per_hour must be > 0 when restart is enabled")
		}
		if s.Restart.Backoff.Duration <= 0 {
			return fmt.Errorf("worker desired state: restart.backoff must be > 0 when restart is enabled")
		}
		if s.Restart.BackoffMax.Duration <= 0 {
			return fmt.Errorf("worker desired state: restart.backoff_max must be > 0 when restart is enabled")
		}
		if s.Restart.Backoff.Duration > s.Restart.BackoffMax.Duration {
			return fmt.Errorf("worker desired state: restart.backoff must not exceed restart.backoff_max")
		}
	}
	if s.UpdatedAt.IsZero() {
		return fmt.Errorf("worker desired state: updated_at is required")
	}
	return nil
}

// WorkerSupervisor reconciles durable desired worker state with the live
// server-owned worker registry.
type WorkerSupervisor struct {
	manager *WorkerManager

	mu               sync.Mutex
	seenTerminals    map[string]time.Time
	blockedTerminals map[string]string
	restartEvents    []time.Time
}

// NewWorkerSupervisor returns a supervisor for the given manager.
func NewWorkerSupervisor(m *WorkerManager) *WorkerSupervisor {
	return &WorkerSupervisor{
		manager:          m,
		seenTerminals:    map[string]time.Time{},
		blockedTerminals: map[string]string{},
	}
}

func (s *WorkerSupervisor) desiredStatePath() string {
	if s == nil || s.manager == nil {
		return ""
	}
	return filepath.Join(s.manager.rootDir, "desired.json")
}

// SaveDesiredState normalizes, validates, and persists the desired worker
// state. UpdatedAt is refreshed on every save.
func (s *WorkerSupervisor) SaveDesiredState(state *WorkerDesiredState) error {
	if s == nil || s.manager == nil {
		return fmt.Errorf("worker supervisor is not configured")
	}
	if state == nil {
		return fmt.Errorf("worker desired state is required")
	}

	state.ApplyDefaults(s.manager.projectRoot)
	state.UpdatedAt = time.Now().UTC()
	if err := state.Validate(); err != nil {
		return err
	}

	if err := os.MkdirAll(s.manager.rootDir, 0o755); err != nil {
		return err
	}
	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return err
	}
	data = append(data, '\n')
	tmp := s.desiredStatePath() + ".tmp"
	if err := os.WriteFile(tmp, data, 0o644); err != nil {
		return err
	}
	return os.Rename(tmp, s.desiredStatePath())
}

// LoadDesiredState reads and validates the durable desired-state file.
func (s *WorkerSupervisor) LoadDesiredState() (WorkerDesiredState, error) {
	if s == nil || s.manager == nil {
		return WorkerDesiredState{}, fmt.Errorf("worker supervisor is not configured")
	}

	data, err := os.ReadFile(s.desiredStatePath())
	if err != nil {
		return WorkerDesiredState{}, err
	}

	var state WorkerDesiredState
	if err := json.Unmarshal(data, &state); err != nil {
		return WorkerDesiredState{}, err
	}
	if state.ProjectRoot != "" && state.ProjectRoot != s.manager.projectRoot {
		return WorkerDesiredState{}, fmt.Errorf("worker desired state: project_root %q does not match manager root %q", state.ProjectRoot, s.manager.projectRoot)
	}
	state.ApplyDefaults(s.manager.projectRoot)
	if err := state.Validate(); err != nil {
		return WorkerDesiredState{}, err
	}
	return state, nil
}

// Reconcile loads the desired state and brings the worker registry toward it.
func (s *WorkerSupervisor) Reconcile() error {
	return s.ReconcileAt(time.Now().UTC())
}

// ReconcileAt is the deterministic reconciliation entry point used by tests.
func (s *WorkerSupervisor) ReconcileAt(now time.Time) error {
	if s == nil || s.manager == nil {
		return fmt.Errorf("worker supervisor is not configured")
	}

	state, err := s.LoadDesiredState()
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return nil
		}
		return err
	}

	projectRoot := state.ProjectRoot
	if projectRoot == "" {
		projectRoot = s.manager.projectRoot
	}

	active, running, terminals, staleIDs, err := s.snapshotWorkers(projectRoot)
	if err != nil {
		return err
	}

	for _, id := range staleIDs {
		if err := s.manager.stopStaleDiskEntry(id); err != nil {
			return err
		}

package server

import (
	"encoding/json"
	"os"
	"path/filepath"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
)

// reportedWorkersAdapter adapts the in-memory worker_ingest registry to the
// ddxgraphql.ReportedWorkersProvider interface used by the reportedWorkers
// query. It also synthesizes in-flight attempts from run-state.json as
// active workers. now is overridable so tests can advance the freshness
// clock without mutating registry timestamps.
type reportedWorkersAdapter struct {
	reg        *workerIngestRegistry
	workingDir string
	mu         sync.RWMutex
	now        func() time.Time
}

func newReportedWorkersAdapter(reg *workerIngestRegistry) *reportedWorkersAdapter {
	return &reportedWorkersAdapter{reg: reg, now: func() time.Time { return time.Now().UTC() }}
}

func newReportedWorkersAdapterWithWorkingDir(reg *workerIngestRegistry, workingDir string) *reportedWorkersAdapter {
	return &reportedWorkersAdapter{
		reg:        reg,
		workingDir: workingDir,
		now:        func() time.Time { return time.Now().UTC() },
	}
}

func (a *reportedWorkersAdapter) currentNow() time.Time {
	a.mu.RLock()
	defer a.mu.RUnlock()
	return a.now()
}

// GetReportedWorkers implements ddxgraphql.ReportedWorkersProvider.
// Returns workers from the ingest registry plus synthesized active workers
// from live run-state.json files. The reportedWorkers query shows both
// registered worker reports (from the worker-server HTTP interface, ADR-022)
// and in-flight attempts (from run-state.json for inline work).
func (a *reportedWorkersAdapter) GetReportedWorkers() []*ddxgraphql.ReportedWorker {
	if a.reg == nil {
		return nil
	}
	now := a.currentNow()
	snap := a.reg.snapshot()
	out := make([]*ddxgraphql.ReportedWorker, 0, len(snap))
	for _, rec := range snap {
		w := &ddxgraphql.ReportedWorker{
			ID:                  rec.WorkerID,
			Project:             rec.Identity.ProjectRoot,
			Harness:             rec.Identity.Harness,
			State:               freshnessState(rec, now),
			LastEventAt:         rec.LastEventAt.UTC().Format(time.RFC3339Nano),
			MirrorFailuresCount: rec.MirrorFailuresCount,
			HadDroppedBackfill:  rec.HadDroppedBackfill,
		}
		if rec.CurrentBead != "" {
			cb := rec.CurrentBead
			w.CurrentBead = &cb
		}
		if rec.CurrentAttempt != "" {
			ca := rec.CurrentAttempt
			w.CurrentAttempt = &ca
		}
		out = append(out, w)
	}

	// Synthesize active workers from live run-state.json for inline work.
	if a.workingDir != "" {
		inFlightWorkers := a.getInFlightWorkers(now)
		out = append(out, inFlightWorkers...)
	}

	return out
}

// getInFlightWorkers returns synthesized ReportedWorker entries for each
// live attempt in run-state.json that has not yet expired.
func (a *reportedWorkersAdapter) getInFlightWorkers(now time.Time) []*ddxgraphql.ReportedWorker {
	runStateDir := ddxroot.JoinProject(a.workingDir, agent.RunStateDirName)
	entries, err := os.ReadDir(runStateDir)
	if err != nil {
		return nil
	}

	var out []*ddxgraphql.ReportedWorker
	for _, entry := range entries {
		if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
			continue
		}
		data, err := os.ReadFile(filepath.Join(runStateDir, entry.Name()))
		if err != nil {
			continue
		}
		var state agent.RunState
		if err := json.Unmarshal(data, &state); err != nil {
			continue
		}
		// Skip expired runs.
		if !state.ExpiresAt.IsZero() && now.After(state.ExpiresAt) {
			continue
		}
		// Synthesize a ReportedWorker from the run-state.
		w := &ddxgraphql.ReportedWorker{
			ID:          "inline-" + state.AttemptID,
			Project:     a.workingDir,
			Harness:     state.Harness,
			State:       "connected",
			LastEventAt: state.RefreshedAt.UTC().Format(time.RFC3339Nano),
		}
		if state.BeadID != "" {
			b := state.BeadID
			w.CurrentBead = &b
		}
		if state.AttemptID != "" {
			att := state.AttemptID
			w.CurrentAttempt = &att
		}
		out = append(out, w)
	}
	return out
}

func (m *WorkerManager) StartExecuteLoop(spec ExecuteLoopWorkerSpec) (WorkerRecord, error) {
	// Resolve the effective project root: spec override takes priority over the
	// manager's default so callers can target any registered project.
	effectiveRoot := spec.ProjectRoot
	if effectiveRoot == "" {
		effectiveRoot = m.projectRoot
	}
	spec.ProjectRoot = effectiveRoot
	spec.ApplyDefaults()
	if err := spec.Validate(); err != nil {
		return WorkerRecord{}, err
	}

	// Pre-flight: validate harness availability and model compatibility
	// before creating the worker record or claiming any beads.
	// Skipped when OpaquePassthrough=true (ddx work path): routing belongs to
	// the agent service; DDx must not pre-resolve or validate the route.
	if !spec.OpaquePassthrough {
		if err := agent.ValidateForExecuteLoopViaService(context.Background(), effectiveRoot, spec.Harness, spec.Model, spec.Provider); err != nil {
			return WorkerRecord{}, fmt.Errorf("work: %w", err)
		}
	}

	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	id := "worker-" + time.Now().UTC().Format("20060102T150405") + "-" + randomSuffix(4)
	dir := filepath.Join(m.rootDir, id)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	// Write spec
	specData, _ := json.MarshalIndent(spec, "", "  ")
	_ = os.WriteFile(filepath.Join(dir, "spec.json"), append(specData, '\n'), 0o644)

	// Open log file
	logPath := filepath.Join(dir, "worker.log")
	logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if err != nil {
		return WorkerRecord{}, err
	}

	// Open structured event sink — loop milestones (bead.claimed, bead.result,
	// loop.start/end) land here as JSONL so log aggregators and future server
	// endpoints can parse them independently of the human-readable worker.log.
	eventsPath := filepath.Join(dir, "worker-events.jsonl")
	eventsFile, eventsErr := os.OpenFile(eventsPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if eventsErr != nil {
		eventsFile = nil // non-fatal; structured events silently disabled
	}

	record := WorkerRecord{
		ID:           id,
		Kind:         "work",
		State:        "running",
		Status:       "running",
		ProjectRoot:  effectiveRoot,
		Harness:      spec.Harness,
		Model:        spec.Model,
		Profile:      agent.NormalizeRoutingProfile(spec.Profile),
		Effort:       spec.Effort,
		Once:         executeLoopOnce(spec),
		PollInterval: executeLoopPollInterval(spec).String(),
		StdoutPath:   relToProject(m.projectRoot, logPath),
		SpecPath:     relToProject(m.projectRoot, filepath.Join(dir, "spec.json")),
		StartedAt:    time.Now().UTC(),
	}
	record.Lifecycle = append(record.Lifecycle, WorkerLifecycleEvent{
		Action:    "start",
		Actor:     "local-operator",
		Timestamp: record.StartedAt,
		Detail:    lifecycleStartDetail(spec),
	})
	_ = m.writeRecord(dir, record)

	ctx, cancel := context.WithCancel(context.Background())
	logBuf := &bytes.Buffer{}
	multiLog := io.MultiWriter(logBuf, logFile)

	progressCh := make(chan agent.ProgressEvent, 64)
	wakeCh := make(chan struct{}, 1)
	handle := &workerHandle{
		record:       record,
		cancel:       cancel,
		logBuf:       logBuf,
		logFile:      logFile,
		progressCh:   progressCh,
		progressDone: make(chan struct{}),
		lastPhaseTS:  time.Now().UTC(),
		wakeCh:       wakeCh,
	}

	m.mu.Lock()
	m.workers[id] = handle
	m.mu.Unlock()

	m.ensureWatchdog()

	go m.drainProgress(id, handle, progressCh)
	go m.runWorker(ctx, id, dir, spec, effectiveRoot, handle, multiLog, eventsFile, progressCh)

	return record, nil
}

func (m *WorkerManager) StartPluginAction(spec PluginActionWorkerSpec, run PluginActionExecutor) (WorkerRecord, error) {
	if run == nil {
		return WorkerRecord{}, fmt.Errorf("plugin action executor is required")
	}

	effectiveRoot := spec.ProjectRoot
	if effectiveRoot == "" {
		effectiveRoot = m.projectRoot
	}

	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	id := "worker-" + time.Now().UTC().Format("20060102T150405") + "-" + randomSuffix(4)
	dir := filepath.Join(m.rootDir, id)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	spec.ProjectRoot = effectiveRoot
	specData, _ := json.MarshalIndent(spec, "", "  ")
	_ = os.WriteFile(filepath.Join(dir, "spec.json"), append(specData, '\n'), 0o644)

	logPath := filepath.Join(dir, "worker.log")
	logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if err != nil {
		return WorkerRecord{}, err
	}

	startedAt := time.Now().UTC()
	record := WorkerRecord{
		ID:          id,
		Kind:        "plugin-dispatch",
		State:       "running",
		Status:      "running",
		ProjectRoot: effectiveRoot,
		StdoutPath:  relToProject(m.projectRoot, logPath),
		SpecPath:    relToProject(m.projectRoot, filepath.Join(dir, "spec.json")),
		StartedAt:   startedAt,
		Lifecycle: []WorkerLifecycleEvent{{
			Action:    "start",
			Actor:     "local-operator",
			Timestamp: startedAt,
			Detail:    fmt.Sprintf("%s plugin %s (%s)", spec.Action, spec.Name, spec.Scope),
		}},
	}
	_ = m.writeRecord(dir, record)

	ctx, cancel := context.WithCancel(context.Background())
	logBuf := &bytes.Buffer{}
	multiLog := io.MultiWriter(logBuf, logFile)
	progressCh := make(chan agent.ProgressEvent, 16)
	handle := &workerHandle{
		record:       record,
		cancel:       cancel,
		logBuf:       logBuf,
		logFile:      logFile,
		progressCh:   progressCh,
		progressDone: make(chan struct{}),
		lastPhaseTS:  startedAt,
	}

	m.mu.Lock()
	m.workers[id] = handle
	m.mu.Unlock()

	m.ensureWatchdog()

	go m.drainProgress(id, handle, progressCh)
	go m.runPluginAction(ctx, id, dir, spec, handle, multiLog, progressCh, run)

	return record, nil
}

func (m *WorkerManager) runPluginAction(ctx context.Context, id, dir string, spec PluginActionWorkerSpec, handle *workerHandle, log io.Writer, progressCh chan agent.ProgressEvent, run PluginActionExecutor) {
	startedAt := time.Now().UTC()
	phaseSeq := 1
	sendProgress(progressCh, agent.ProgressEvent{
		EventID:   "evt-" + randomSuffix(8),
		AttemptID: id,
		WorkerID:  id,
		ProjectID: spec.ProjectRoot,
		Phase:     "running",
		PhaseSeq:  phaseSeq,
		TS:        startedAt,
		Message:   fmt.Sprintf("%s plugin %s", spec.Action, spec.Name),
	})
	if log != nil {
		_, _ = fmt.Fprintf(log, "%s plugin %s (%s)\n", spec.Action, spec.Name, spec.Scope)
	}

	state, err := run(ctx)
	if ctxErr := ctx.Err(); ctxErr != nil && err == nil {
		err = ctxErr
	}

	phase := "done"
	message := state
	if err != nil {
		phase = "failed"
		message = err.Error()
	}
	phaseSeq++
	sendProgress(progressCh, agent.ProgressEvent{
		EventID:   "evt-" + randomSuffix(8),
		AttemptID: id,
		WorkerID:  id,
		ProjectID: spec.ProjectRoot,
		Phase:     phase,
		PhaseSeq:  phaseSeq,
		TS:        time.Now().UTC(),
		ElapsedMS: time.Since(startedAt).Milliseconds(),
		Message:   message,
	})

	if log != nil {
		if err != nil {
			_, _ = fmt.Fprintf(log, "failed: %s\n", err)
		} else {
			_, _ = fmt.Fprintf(log, "completed: %s\n", state)
		}
	}

	close(progressCh)
	<-handle.progressDone

	m.mu.Lock()
	record := handle.record
	preservedState := ""
	if record.State == "stopped" || record.State == "reaped" {
		preservedState = record.State
	}
	record.FinishedAt = time.Now().UTC()
	_ = handle.logFile.Close()
	if err != nil {
		record.State = "failed"
		record.Status = "failed"
		record.Error = err.Error()
		record.LastError = err.Error()
	} else {
		record.State = "exited"
		record.Status = "success"
		record.LastResult = &WorkerExecutionResult{
			AttemptID:  id,
			WorkerID:   id,
			PowerClass: "",
			Status:     state,
			Detail:     fmt.Sprintf("%s plugin %s", spec.Action, spec.Name),
		}
	}
	if preservedState != "" {
		record.State = preservedState
		record.Status = preservedState
	}
	_ = m.writeRecord(dir, record)
	handle.record = record
	m.mu.Unlock()
}

func sendProgress(ch chan<- agent.ProgressEvent, evt agent.ProgressEvent) {
	select {
	case ch <- evt:
	default:
	}
}

func isBudgetExhaustedFailure(report agent.ExecuteBeadReport) bool {
	return strings.Contains(report.Detail, agent.RateLimitBudgetExhaustedReason)
}

func nextEscalationFloor(l *powerladder.Ladder, actualPower int) (int, error) {
	if l == nil {
		return 0, powerladder.ErrLadderExhausted
	}
	floor := actualPower
	for {
		next, err := l.Next(floor)
		if err == nil {
			return next, nil
		}
		var nvp *powerladder.NoViableProviderError
		if errors.As(err, &nvp) {
			floor = nvp.Floor
			continue
		}
		return 0, err
	}
}

type tryLoopFloorFinder struct {
	ladder *powerladder.Ladder
}

func (f tryLoopFloorFinder) Next(actualPower int) (int, error) {
	return nextEscalationFloor(f.ladder, actualPower)
}

func runEscalatingPowerAttempts(
	ctx context.Context,
	initialMinPower int,
	ladder *powerladder.Ladder,
	attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
	recordAttempt func(agent.ExecuteBeadReport),
	allowInfrastructureRetry bool,
) (agent.ExecuteBeadReport, error) {
	minPower := initialMinPower
	floors := tryLoopFloorFinder{ladder: ladder}
	for {
		report, err := attempt(ctx, minPower)
		if recordAttempt != nil && report.BeadID != "" {
			recordAttempt(report)
		}
		if err != nil {
			return report, err
		}
		transition := executeloop.DecideAttemptTransition(executeloop.AttemptTransitionInput{
			Status:                   report.Status,
			Detail:                   report.Detail,
			CurrentMinPower:          minPower,
			ActualPower:              report.ActualPower,
			Disrupted:                report.Disrupted,
			BudgetExhausted:          isBudgetExhaustedFailure(report),
			AllowInfrastructureRetry: allowInfrastructureRetry,
		}, floors)
		if transition.Action != executeloop.TryLoopActionRetryPower {
			return report, nil
		}
		minPower = transition.NextMinPower
	}
}

func appendPowerAttemptEvent(store agent.BeadEventAppender, beadID string, report agent.ExecuteBeadReport, actor string, createdAt time.Time) {
	if store == nil || beadID == "" {
		return
	}
	body := policyescalation.FormatPowerAttemptBody(report.PowerClass, report.Harness, report.Model, report.ProbeResult, report.Detail)
	summary := report.Status
	if report.PowerClass != "" {
		summary = fmt.Sprintf("%s powerClass=%s", summary, report.PowerClass)
	}
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "power-attempt",
		Summary:   summary,
		Body:      body,
		Actor:     actor,
		Source:    "legacy agent work",
		CreatedAt: createdAt,
	})
}

func (m *WorkerManager) runWorker(ctx context.Context, id, dir string, spec ExecuteLoopWorkerSpec, projectRoot string, handle *workerHandle, log io.Writer, eventSink io.WriteCloser, progressCh chan agent.ProgressEvent) {
	if eventSink != nil {
		defer eventSink.Close() //nolint:errcheck
	}
	store := bead.NewStore(ddxroot.JoinProject(projectRoot))
	overrides := config.CLIOverrides{
		Assignee:          "ddx",
		Harness:           spec.Harness,
		Model:             spec.Model,
		Provider:          spec.Provider,
		Profile:           agent.NormalizeRoutingProfile(spec.Profile),
		Effort:            spec.Effort,
		MinPower:          spec.MinPower,
		MaxPower:          spec.MaxPower,
		OpaquePassthrough: spec.OpaquePassthrough,
	}
	requestTimeout := spec.RequestTimeout.Duration
	if requestTimeout > 0 {
		overrides.ProviderRequestTimeout = &requestTimeout
	}
	rcfg, _ := config.LoadAndResolve(projectRoot, overrides)

	var lintHook func(ctx context.Context, beadID string) (agent.LintResult, error)
	var intakeHook agent.PreClaimIntakeHook
	var triageHook func(ctx context.Context, beadID string, report agent.ExecuteBeadReport) (agent.TriageResult, error)
	if m.BeadWorkerFactory == nil {
		var qualityRunner agent.AgentRunner
		lintHook = agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
		intakeHook = agent.NewPreClaimIntakeHookWithLog(projectRoot, store, rcfg, nil, qualityRunner, log)
		intakeHook = agent.NewACQualityPreClaimGate(store, rcfg.BeadQualityMode(), rcfg.ACQualityMinScore(), intakeHook)
		triageHook = agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)
	}

	var worker *agent.ExecuteBeadWorker
	var costCap *policyescalation.CostCapTracker
	if m.BeadWorkerFactory != nil {
		worker = m.BeadWorkerFactory(store)
	} else {
		// Build an executor that calls agent.ExecuteBead in-process, then
		// submits the result to the project's land coordinator. The
		// coordinator (a single goroutine per projectRoot) serializes all
		// target-ref writes for this project — this is the server-side
		// implementation of the human-PR landing model. See ddx-8746d8a6
		// for the rationale. Prior to this rewrite, runWorker never called
		// LandBeadResult at all, so commits produced by server-managed
		// workers were silently lost (ddx-e14efc58).
		coordinator := m.LandCoordinators.Get(projectRoot)

		// singlePolicyAttempt runs one execution at a specific harness/model.
		// The caller controls MinPower per rung; this helper keeps the
		// profile stable and only advances the power floor.
		singlePolicyAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
			gitOps := &agent.RealGitOps{}
			attemptProvider := spec.Provider
			if resolvedProvider != "" {
				attemptProvider = resolvedProvider
			}
			loopOverrides := config.CLIOverrides{
				Harness:           resolvedHarness,
				Model:             resolvedModel,
				Provider:          attemptProvider,
				Profile:           rcfg.Profile(),
				Effort:            spec.Effort,
				MinPower:          requestedMinPower,
				MaxPower:          spec.MaxPower,
				OpaquePassthrough: spec.OpaquePassthrough,
			}
			if requestTimeout > 0 {
				loopOverrides.ProviderRequestTimeout = &requestTimeout
			}
			attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
			beadStore := bead.NewStore(ddxroot.JoinProject(projectRoot))
			res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
				FromRev:          spec.FromRev,
				BeadEvents:       beadStore,
				BeadCancel:       beadStore,
				RateLimitMaxWait: spec.RateLimitMaxWait.Duration,
			}, gitOps)
			if err != nil && res == nil {
				return agent.ExecuteBeadReport{}, err
			}
			// Preserve operator-cancel results as-is; the worker has already
			// classified them (preserved / operator_cancel / preserved_needs_review)
			// and overriding here would lose the cancel signal.
			operatorCancel := res != nil && res.Reason == agent.OperatorCancelReason
			if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 && !operatorCancel {
				if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
					err = landErr
				}
			} else if res != nil && res.ResultRev == res.BaseRev && !operatorCancel {
				res.Outcome = "no-changes"
				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
			} else if res != nil && res.ExitCode != 0 && !operatorCancel {
				res.Outcome = "preserved"
				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
			}
			// Safety net: commit any leftover evidence files that Land()
			// did not pick up (e.g. HEAD was detached, or no land ran).
			if res != nil && res.AttemptID != "" {
				_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
			}
			if err != nil {
				return agent.ExecuteBeadReport{}, err
			}
			return agent.ExecuteBeadReport{
				BeadID:             res.BeadID,
				AttemptID:          res.AttemptID,
				WorkerID:           res.WorkerID,
				Harness:            res.Harness,
				Provider:           res.Provider,
				Model:              res.Model,
				ActualPower:        res.ActualPower,
				Status:             res.Status,
				Detail:             res.Detail,
				SessionID:          res.SessionID,
				BaseRev:            res.BaseRev,
				ResultRev:          res.ResultRev,
				ImplementationRev:  res.ImplementationRev,
				LandedRev:          res.LandedRev,
				EvidenceRev:        res.EvidenceRev,
				PreserveRef:        res.PreserveRef,
				NoChangesRationale: res.NoChangesRationale,
				CostUSD:            res.CostUSD,
				DurationMS:         int64(res.DurationMS),
			}, nil
		}

		// Cost-cap state for this worker run. Subscription / local providers do
		// not contribute (see escalation.CountsTowardCostCap).
		maxCostUSD := executeLoopMaxCostUSD(spec)
		var ladderOnce sync.Once
		var ladder *powerladder.Ladder
		loadLadder := func() *powerladder.Ladder {
			ladderOnce.Do(func() {
				ladder = powerladder.NewLadder(nil)
				modelCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
				defer cancel()
				// Tie the fizeau service to modelCtx so its background probe
				// goroutines terminate when this short-lived lookup ends.
				if svc, svcErr := agent.NewServiceFromWorkDirCtx(modelCtx, projectRoot); svcErr == nil {
					modelFilter := agentlib.ModelFilter{}
					if harness := rcfg.Harness(); harness != "" {
						modelFilter.Harness = harness
					}
					if models, listErr := svc.ListModels(modelCtx, modelFilter); listErr == nil {
						ladder = powerladder.NewLadder(models)
					}
				}
			})
			return ladder
		}
		costCap = policyescalation.NewCostCapTracker(maxCostUSD, func(harnessName string) bool {
			// Per-callback bounded ctx so fizeau probe goroutines do not
			// outlive this cost-cap check.
			cbCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
			defer cancel()
			svc, svcErr := agent.NewServiceFromWorkDirCtx(cbCtx, projectRoot)
			if svcErr != nil {
				return true
			}
			infos, err := svc.ListHarnesses(cbCtx)
			if err != nil {
				return true
			}
			for _, h := range infos {
				if h.Name == harnessName {
					return policyescalation.CountsTowardCostCap(h.CostClass == "local", h.Billing == agentlib.BillingModelSubscription, h.CostClass)
				}
			}
			return true
		})
		accumulateBilledCost := func(report agent.ExecuteBeadReport) {
			costCap.Add(report.Harness, report.CostUSD)
		}
		costCapTripped := func() (agent.ExecuteBeadReport, bool) {
			if _, tripped := costCap.Tripped(); !tripped {
				return agent.ExecuteBeadReport{}, false
			}
			spent := costCap.Spent()
			return agent.ExecuteBeadReport{
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, maxCostUSD),
			}, true
		}
		attemptWithCostCap := func(ctx context.Context, beadID string, requestedMinPower int) (agent.ExecuteBeadReport, error) {
			if cappedReport, capped := costCapTripped(); capped {
				cappedReport.BeadID = beadID
				return cappedReport, nil
			}
			report, err := singlePolicyAttempt(ctx, beadID, requestedMinPower, spec.Harness, spec.Provider, spec.Model)
			if err == nil {
				accumulateBilledCost(report)
				if cappedReport, capped := costCapTripped(); capped {
					cappedReport.BeadID = beadID
					return cappedReport, nil
				}
			}
			return report, err
		}

		executor := agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
			attempts := make([]policyescalation.PowerAttemptRecord, 0, 3)
			recordAttempt := func(report agent.ExecuteBeadReport) {
				if report.PowerClass == "" && report.Harness == "" && report.Model == "" && report.ProbeResult == "" && report.CostUSD == 0 && report.DurationMS == 0 {
					return
				}
				attempts = append(attempts, policyescalation.PowerAttemptRecord{
					PowerClass: report.PowerClass,
					Harness:    report.Harness,
					Model:      report.Model,
					Status:     report.Status,
					CostUSD:    report.CostUSD,
					DurationMS: report.DurationMS,
				})
				appendPowerAttemptEvent(store, beadID, report, "ddx", time.Now().UTC())
			}
			report, err := runEscalatingPowerAttempts(ctx, rcfg.MinPower(), loadLadder(), func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
				return attemptWithCostCap(ctx, beadID, requestedMinPower)
			}, recordAttempt, strings.TrimSpace(spec.Harness) == "" && strings.TrimSpace(spec.Provider) == "" && strings.TrimSpace(spec.Model) == "")
			if len(attempts) > 0 {
				winningPowerClass := ""
				if report.Status == agent.ExecuteBeadStatusSuccess && report.PowerClass != "" {
					winningPowerClass = report.PowerClass
				}
				_ = policyescalation.AppendEscalationSummaryEvent(store, beadID, "ddx", attempts, winningPowerClass, time.Now().UTC())
			}
			return report, err
		})

		// Build post-merge reviewer. On-by-default unless NoReview is set in spec.
		var reviewer agent.BeadReviewer
		if !spec.NoReview {
			reviewer = &agent.DefaultBeadReviewer{
				ProjectRoot: projectRoot,
				BeadStore:   bead.NewStore(ddxroot.JoinProject(projectRoot)),
				BeadEvents:  bead.NewStore(ddxroot.JoinProject(projectRoot)),
				Harness:     spec.ReviewHarness,
				Model:       spec.ReviewModel,
			}
		}

		worker = &agent.ExecuteBeadWorker{
			Store:    store,
			Executor: executor,
			Reviewer: reviewer,
		}
	}

	landingOps := agent.RealLandingGitOps{}

	loopResult, err := worker.Run(ctx, rcfg, agent.ExecuteBeadLoopRuntime{
		Mode:                  spec.Mode,
		IdleInterval:          executeLoopPollInterval(spec),
		Log:                   log,
		CleanupLog:            log,
		EventSink:             eventSink,
		WorkerID:              id,
		ProjectRoot:           projectRoot,
		CleanupRunner:         agent.NewExecutionCleanupManager(projectRoot, &agent.RealGitOps{}),
		LabelFilter:           spec.LabelFilter,
		ProgressCh:            progressCh,
		PreClaimHook:          buildPreClaimHook(projectRoot, landingOps),
		PreClaimIntakeHook:    intakeHook,
		PreDispatchLintHook:   lintHook,
		PostAttemptTriageHook: triageHook,
		NoReview:              spec.NoReview,
		ReviewCostCap:         costCap,
		WakeCh:                handle.wakeCh,
	})
	// Signal end of progress events so drainProgress can finish
	close(progressCh)
	// Wait for drainProgress to process all remaining events (including live
	// counter increments) before we overwrite handle.record with the final state.
	<-handle.progressDone

	m.mu.Lock()
	record := handle.record
	// Preserve terminal state set by Stop() or the watchdog so the final
	// writeRecord below does not overwrite "stopped" / "reaped" with
	// "exited" / "failed".
	preservedState := ""
	if record.State == "stopped" || record.State == "reaped" {
		preservedState = record.State
	}
	record.FinishedAt = time.Now().UTC()
	// Terminal worker: clear any "idle" substate (ddx-dc157075 AC #5; substate
	// is only meaningful while the worker is running).
	record.Substate = ""
	_ = handle.logFile.Close()

	if err != nil {
		record.State = "failed"
		record.Status = "failed"
		record.Error = err.Error()
		record.LastError = err.Error()
	} else {
		record.State = "exited"
		record.Attempts = loopResult.Attempts
		record.Successes = loopResult.Successes
		record.Failures = loopResult.Failures

		if loopResult.NoReadyWork {
			record.Status = "no_ready_work"
		} else if loopResult.Failures > 0 && loopResult.Successes == 0 {
			record.Status = "execution_failed"
			if loopResult.LastFailureStatus != "" {
				record.Status = loopResult.LastFailureStatus
			}
		} else if loopResult.Successes > 0 {
			record.Status = "success"
		} else {
			record.Status = "exited"
		}

		if len(loopResult.Results) > 0 {
			last := loopResult.Results[len(loopResult.Results)-1]
			r := WorkerExecutionResult{
				BeadID:            last.BeadID,
				AttemptID:         last.AttemptID,
				WorkerID:          last.WorkerID,
				Harness:           last.Harness,
				PowerClass:        last.PowerClass,
				Provider:          last.Provider,
				Model:             last.Model,
				Status:            last.Status,
				Detail:            last.Detail,
				SessionID:         last.SessionID,
				BaseRev:           last.BaseRev,
				ResultRev:         last.ResultRev,
				ImplementationRev: last.ImplementationRev,
				LandedRev:         last.LandedRev,
				EvidenceRev:       last.EvidenceRev,
				RetryAfter:        last.RetryAfter,
			}
			record.CurrentBead = last.BeadID
			record.LastResult = &r
			if last.Detail != "" {
				record.LastError = last.Detail
			}
			if last.Harness != "" && record.Harness == "" {
				record.Harness = last.Harness
			}
			if last.Model != "" && record.Model == "" {
				record.Model = last.Model
			}
			if last.Provider != "" && record.Provider == "" {
				record.Provider = last.Provider
			}
		}
	}
	// Terminal-state override: if Stop() or the watchdog already marked
	// this worker, keep that label so external consumers see the reason.
	if preservedState != "" {
		record.State = preservedState
		record.Status = preservedState
	}
	_ = m.writeRecord(dir, record)
	handle.record = record
	m.mu.Unlock()
}

func (m *WorkerManager) List() ([]WorkerRecord, error) {
	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return nil, err
	}
	entries, err := os.ReadDir(m.rootDir)
	if err != nil {
		return nil, err
	}
	var out []WorkerRecord
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		rec, err := m.readRecord(filepath.Join(m.rootDir, entry.Name()))
		if err != nil {
			continue
		}
		if !isWorkerRegistryRecord(rec) {
			continue
		}
		out = append(out, rec)
	}

	// Merge in-memory state for active workers
	m.mu.Lock()
	for i := range out {
		if handle, ok := m.workers[out[i].ID]; ok {
			out[i] = handle.record
		}
	}
	m.mu.Unlock()

	sort.Slice(out, func(i, j int) bool {
		return out[i].StartedAt.After(out[j].StartedAt)
	})

	// Compute PIDAlive for each record so operators can see liveness at a
	// glance without running prune. This is a syscall per record; it's safe
	// because List() is not on a hot path (workers are long-lived).
	for i := range out {
		if out[i].PID > 0 {
			alive := isPIDAlive(out[i].PID)
			out[i].PIDAlive = &alive
		}
	}

	return out, nil

	assert.Equal(t, 7*time.Minute, s)
	assert.Equal(t, defaultWatchdogCheckInterval, c)
	assert.Equal(t, defaultWatchdogKillGrace, g)
