// workerProcessCleanupReport captures the process groups a stop/reap cleanup
// targeted so callers can report which tree was signaled and which groups
// needed escalation.
type workerProcessCleanupReport struct {
	PrimaryPGID  int
	ChildPGIDs   []int
	TargetPGIDs  []int
	SIGTERMPGIDs []int
	SIGKILLPGIDs []int
}

func uniqueProcessGroupIDs(primaryPGID int, childPGIDs []int) []int {
	seen := make(map[int]struct{}, 1+len(childPGIDs))
	out := make([]int, 0, 1+len(childPGIDs))
	add := func(pgid int) {
		if pgid <= 0 {
			return
		}
		if _, ok := seen[pgid]; ok {
			return
		}
		seen[pgid] = struct{}{}
		out = append(out, pgid)
	}

	add(primaryPGID)
	for _, pgid := range childPGIDs {
		add(pgid)
	}
	return out
}

