func signalProcessGroup(pgid int, sig syscall.Signal) {
	if pgid <= 0 {
		return
	}
	_ = syscall.Kill(-pgid, sig)
}

func aliveProcessGroups(pgids []int) []int {
	out := make([]int, 0, len(pgids))
	for _, pgid := range pgids {
		if processGroupAlive(pgid) {
			out = append(out, pgid)
		}
	}
	return out
}

// terminateProcessGroup sends SIGTERM to the worker's process group; if the
// process group is still alive after grace, follows up with SIGKILL. The
// negative pgid argument to syscall.Kill targets the whole process group,
// which is essential for workers that fork child harnesses.
//
// Callers set Setpgid=true when spawning the process so pid == pgid and the
// group id matches. If the caller did not set a new pgid, a negative-pgid
// signal still works because the worker's own pgid will be the caller's pgid
// - not desirable, so the caller contract is: only register a PID for
// processes you spawned with their own pgid.
func terminateProcessGroup(pgid int, grace time.Duration) {
	if pgid <= 0 {
		return
	}
	// SIGTERM to the process group.
	signalProcessGroup(pgid, syscall.SIGTERM)

	// Poll until grace expires for the whole process group to exit; then
	// SIGKILL any remaining members.
	deadline := time.Now().Add(grace)
	for time.Now().Before(deadline) {
		if !processGroupAlive(pgid) {
			return
		}
		time.Sleep(100 * time.Millisecond)
	}
	signalProcessGroup(pgid, syscall.SIGKILL)
}

// terminateManagedWorkerProcessTree sends SIGTERM to the managed worker's own
// PGID and any registered child process groups. It waits one grace window for
// the groups to exit, escalates any survivors to SIGKILL, and returns the
// groups it targeted so callers can report what was cleaned up.
func terminateManagedWorkerProcessTree(primaryPGID int, childPGIDs []int, grace time.Duration) workerProcessCleanupReport {
	targets := uniqueProcessGroupIDs(primaryPGID, childPGIDs)
	report := workerProcessCleanupReport{
		PrimaryPGID: primaryPGID,
		ChildPGIDs:  append([]int(nil), childPGIDs...),
		TargetPGIDs: append([]int(nil), targets...),
	}
	if len(targets) == 0 {
		return report
	}

	for _, pgid := range targets {
		signalProcessGroup(pgid, syscall.SIGTERM)
	}
	report.SIGTERMPGIDs = append([]int(nil), targets...)

	deadline := time.Now().Add(grace)
	remaining := aliveProcessGroups(targets)
	for len(remaining) > 0 && time.Now().Before(deadline) {
		time.Sleep(100 * time.Millisecond)
		remaining = aliveProcessGroups(remaining)
	}
	if len(remaining) == 0 {
		return report
	}

	report.SIGKILLPGIDs = append([]int(nil), remaining...)
	for _, pgid := range remaining {
		signalProcessGroup(pgid, syscall.SIGKILL)
	}

	deadline = time.Now().Add(grace)
	remaining = aliveProcessGroups(remaining)
	for len(remaining) > 0 && time.Now().Before(deadline) {
		time.Sleep(100 * time.Millisecond)
		remaining = aliveProcessGroups(remaining)
	}

	return report
}

